package entity_test

import (
	"math"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench100AEEEC(t *testing.T) {
	tests := []struct {
		name     string
		items    []entity.OrderItem
		expected float64
	}{
		{
			name:     "EmptyItems",
			items:    nil,
			expected: 0,
		},
		{
			name: "ZeroQuantity",
			items: []entity.OrderItem{
				{Quantity: 0, Price: 10.0},
			},
			expected: 0,
		},
		{
			name: "NegativePrice",
			items: []entity.OrderItem{
				{Quantity: 2, Price: -5.0},
			},
			expected: -10.0,
		},
		{
			name: "LargeQuantity",
			items: []entity.OrderItem{
				{Quantity: 1_000_000_000, Price: 0.99},
			},
			expected: 990_000_000.0,
		},
		{
			name: "MixedPositiveAndZero",
			items: []entity.OrderItem{
				{Quantity: 2, Price: 3.5},
				{Quantity: 0, Price: 100.0},
				{Quantity: 5, Price: 0.0},
			},
			expected: 7.0,
		},
		{
			name: "MixedPositiveZeroNegative",
			items: []entity.OrderItem{
				{Quantity: 3, Price: 4.0},
				{Quantity: 0, Price: 50.0},
				{Quantity: 2, Price: -1.5},
			},
			expected: 12.0 - 3.0, // 3*4 + 2*(-1.5) = 12 - 3 = 9
		},
	}

	for _, tc := range tests {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			order := entity.Order{
				Items: tc.items,
			}
			order.CalculateTotal()
			if diff := math.Abs(order.Total - tc.expected); diff > 1e-9 {
				t.Errorf("expected total %v, got %v (diff %v)", tc.expected, order.Total, diff)
			}
		})
	}
}

