package entity_test

import (
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench2FFDF994(t *testing.T) {
	tests := []struct {
		name      string
		content   string
		maxRunes  int
		expected  string
	}{
		{
			name:     "truncate with ellipsis after ASCII and multibyte",
			content:  "Hello世界😀",
			maxRunes: 5,
			// first 5 runes: H e l l o -> "Hello", then ellipsis
			expected: "Hello...",
		},
		{
			name:     "exact boundary no ellipsis (CJK)",
			content:  "日本語テスト",
			maxRunes: 6,
			expected: "日本語テスト",
		},
		{
			name:     "maxRunes <=3 no ellipsis, truncate emojis",
			content:  "😀🎉🍕🎸",
			maxRunes: 3,
			expected: "😀🎉🍕",
		},
		{
			name:     "maxRunes <=3 no ellipsis, exact length",
			content:  "😀🎉🍕🎸",
			maxRunes: 4,
			expected: "😀🎉🍕🎸",
		},
		{
			name:     "maxRunes <=3 truncate mixed ASCII and emoji",
			content:  "A😀B",
			maxRunes: 2,
			expected: "A😀",
		},
		{
			name:     "ellipsis added after emoji truncation",
			content:  "😀😀😀😀😀",
			maxRunes: 4,
			expected: "😀😀😀😀...",
		},
		{
			name:     "maxRunes zero returns empty string",
			content:  "Anything",
			maxRunes: 0,
			expected: "",
		},
		{
			name:     "maxRunes one returns first rune without ellipsis",
			content:  "😀ABC",
			maxRunes: 1,
			expected: "😀",
		},
		{
			name:     "maxRunes two returns first two runes without ellipsis",
			content:  "😀ABC",
			maxRunes: 2,
			expected: "😀A",
		},
		{
			name:     "maxRunes three returns first three runes without ellipsis",
			content:  "😀ABC",
			maxRunes: 3,
			expected: "😀AB",
		},
		{
			name:     "maxRunes four returns first four runes with ellipsis",
			content:  "😀ABCDEF",
			maxRunes: 4,
			expected: "😀ABC...",
		},
	}

	for _, tt := range tests {
		tt := tt
		t.Run(tt.name, func(t *testing.T) {
			ni := entity.NewsItem{
				Content: tt.content,
			}
			got := ni.Summary(tt.maxRunes)
			if got != tt.expected {
				t.Errorf("Summary(%d) = %q, want %q", tt.maxRunes, got, tt.expected)
			}
		})
	}
}

