package entity_test

// CHOICE: Product.ApplyDiscount — testing NaN and infinite percent edge cases not covered.
import (
	"math"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBenchC2C746F5(t *testing.T) {
	p := &entity.Product{
		Price: 100.0,
	}

	tests := []struct {
		name          string
		percent       float64
		wantIsNaN     bool
		wantIsOriginal bool
	}{
		{
			name:          "NaN percent returns NaN",
			percent:       math.NaN(),
			wantIsNaN:     true,
			wantIsOriginal: false,
		},
		{
			name:          "Positive infinity percent returns original price",
			percent:       math.Inf(1),
			wantIsNaN:     false,
			wantIsOriginal: true,
		},
		{
			name:          "Negative infinity percent returns original price",
			percent:       math.Inf(-1),
			wantIsNaN:     false,
			wantIsOriginal: true,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			got := p.ApplyDiscount(tt.percent)

			if tt.wantIsNaN {
				if !math.IsNaN(got) {
					t.Errorf("ApplyDiscount(%v) = %v, want NaN", tt.percent, got)
				}
				return
			}

			if tt.wantIsOriginal && got != p.Price {
				t.Errorf("ApplyDiscount(%v) = %v, want original price %v", tt.percent, got, p.Price)
			}
		})
	}
}
